// ==============================================
// EXTRAER Y TRANSFORMAR DATOS DESDE SUPABASE
// ==============================================

const data = $json;

// Verificar que tenemos los datos mínimos
if (!data.table_name) {
  console.log('❌ Sin mesa asignada, omitiendo');
  return {
    status: 'SKIP_NO_TABLE',
    message: 'Transacción sin mesa asignada'
  };
}

if (!data.total_amount || parseFloat(data.total_amount) <= 0) {
  console.log('❌ Total 0, omitiendo');
  return {
    status: 'SKIP_ZERO_TOTAL',
    message: 'Transacción con total 0'
  };
}

// Extraer items del webhook_payload original de Dotyk
const webhookPayload = data.webhook_payload || {};
const transaction = webhookPayload.Transaction || webhookPayload;
const allItems = [];

// Procesar TODAS las órdenes
const orders = transaction.Orders || [];
orders.forEach(order => {
  const items = order.Items || [];
  items.forEach(item => {
    const optionsText = (item.ItemOptions || []).length > 0
      ? ` (${item.ItemOptions.map(opt => opt.Name).join(', ')})`
      : '';

    allItems.push({
      productName: (item.ItemData?.Name || 'Producto') + optionsText,
      amount: "1",
      unitPrice: (item.PriceTotal || 0).toString(),
      totalPrice: (item.PriceTotal || 0).toString()
    });
  });
});

// Si no hay items en el payload, crear uno genérico
if (allItems.length === 0) {
  allItems.push({
    productName: 'Consumo',
    amount: '1',
    unitPrice: data.total_amount.toString(),
    totalPrice: data.total_amount.toString()
  });
}

// Formatear fecha para CoverManager
const fecha = data.cuentica_invoice_date || new Date().toISOString().split('T')[0];

// Formato de fecha para printDate
const formatDateTime = (dateStr) => {
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) {
    return new Date().toISOString().slice(0, 19).replace('T', ' ');
  }
  return d.toISOString().slice(0, 19).replace('T', ' ');
};

// Datos de pago
const payments = [{
  type: data.payment_method === 'card' ? 'Tarjeta' : 'Efectivo',
  amount: data.total_amount.toString()
}];

console.log(`✅ Procesando: Mesa ${data.table_name}, Total: ${data.total_amount}€, Items: ${allItems.length}`);

return {
  mesa: data.table_name,
  total: parseFloat(data.total_amount),
  items: allItems,
  payments: payments,
  printDate: formatDateTime(data.created_at || fecha),
  date_start: fecha,
  date_end: fecha,
  transaction_id: data.transaction_id,
  cuentica_identifier: data.cuentica_identifier,
  status: 'VALID_PAYMENT'
};

// ==============================================
// FILTRAR RESERVA Y CONSTRUIR PAYLOAD
// ==============================================

// Obtener datos del ticket del nodo anterior
const datosTicket = $item(0).$node["Extraer y Transformar Datos"].json;
const reservasResponse = $json;

// Validar respuesta
if (!reservasResponse || !reservasResponse.reservs) {
  throw new Error('No se recibió respuesta válida de CoverManager');
}

const reservas = reservasResponse.reservs;
const mesaBuscada = String(datosTicket.mesa).trim();

// Estados válidos en CoverManager:
// 3 = Confirmada, 4 = Recordada, 5 = Sentada, 6 = En barra
// 7 = Postre, 8 = Pagado, 9 = Otro
const estadosValidos = [3, 4, 5, 6, 7, 8, 9];

console.log(`🔍 Buscando reserva para mesa: ${mesaBuscada}`);
console.log(`📋 Reservas encontradas: ${reservas.length}`);

// Buscar reserva que coincida con mesa y estado
const reservaValida = reservas.find(reserva => {
  // Extraer mesas de la reserva
  let mesasReserva = [];
  if (Array.isArray(reserva.tables)) {
    mesasReserva = reserva.tables.map(m => String(m).trim());
  } else if (reserva.tables) {
    mesasReserva = String(reserva.tables).split(',').map(m => m.trim());
  }

  const mesaCoincide = mesasReserva.includes(mesaBuscada);
  const statusNum = parseInt(reserva.status);
  const estadoValido = estadosValidos.includes(statusNum);

  if (mesaCoincide) {
    console.log(`  → Reserva ${reserva.id_reserv}: Mesa ✓, Estado ${statusNum} ${estadoValido ? '✓' : '✗'}`);
  }

  return mesaCoincide && estadoValido;
});

if (!reservaValida) {
  throw new Error(`❌ No se encontró reserva activa para mesa ${mesaBuscada}. Estados válidos: ${estadosValidos.join(', ')}`);
}

const reservaId = reservaValida.id_reserv || reservaValida.id;
if (!reservaId) {
  throw new Error('La reserva encontrada no tiene ID válido');
}

console.log(`✅ Reserva encontrada: ${reservaId}`);

// Construir payload final para CoverManager set_ticket
const payload = {
  id_reserv: reservaId,
  items: datosTicket.items,
  payments: datosTicket.payments,
  printDate: datosTicket.printDate,
  status: "PAID",
  total: datosTicket.total.toString(),
  idTicketExt: datosTicket.cuentica_identifier || datosTicket.transaction_id
};

console.log(`📤 Payload para CoverManager:`, JSON.stringify(payload, null, 2));

return payload;

// ==============================================
// LOG DEL RESULTADO FINAL
// ==============================================

const resultado = $json;

console.log('=== RESULTADO FINAL ===');
console.log('Response:', JSON.stringify(resultado, null, 2));

if (resultado.resp === 1 || resultado.resp === 'ok' || resultado.message === 'Inserted') {
  console.log('✅ Ticket enviado correctamente a CoverManager');
  return {
    success: true,
    message: 'Ticket insertado correctamente',
    response: resultado
  };
} else {
  console.log('❌ Error al enviar ticket:', resultado.message || 'Error desconocido');
  return {
    success: false,
    message: resultado.message || 'Error desconocido',
    response: resultado
  };
}

// Log de transacciones omitidas
console.log(`⏭️ Transacción omitida: ${$json.message}`);
return $json;
